def histogram(test):
    if not test:
        return {}
    words = test.split()
    word_counts = {}
    for word in words:
        if word in word_counts:
            word_counts[word] += 1
        else:
            word_counts[word] = 1
    max_count = max(word_counts.values())
    return {word: count for word, count in word_counts.items() if count == max_count}

