def largest_smallest_integers(lst):
    neg_max = None
    pos_min = None

    for num in lst:
        if num < 0:
            if neg_max is None or num > neg_max:
                neg_max = num
        elif num > 0:
            if pos_min is None or num < pos_min:
                pos_min = num

    return (neg_max, pos_min)

